// Generates the Python script shown on the Done step of the
// cipher-modes lesson. Shows AES-128 in CBC + CTR + GCM using
// `cryptography.hazmat.primitives.ciphers`, with a roundtrip per mode.

export function full_script(_state) {
  return [
    "# Block cipher modes around AES-128 — generated by cloak.moosha.org",
    "# Requires the `cryptography` package: pip install cryptography",
    "",
    "import os",
    "from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes",
    "from cryptography.hazmat.primitives.ciphers.aead import AESGCM",
    "from cryptography.hazmat.primitives import padding",
    "",
    "key = os.urandom(16)   # AES-128 key, reused across all three demos below",
    "message = b\"YELLOW SUBMARINE\" * 3   # 48 bytes — 3 full AES blocks",
    "",
    "# ---------------------------------------------------------------",
    "# CBC — chained blocks, requires padding when the message isn't",
    "# block-aligned. We pad with PKCS#7 even though our message already",
    "# is, because real code can't assume block alignment.",
    "# ---------------------------------------------------------------",
    "iv = os.urandom(16)",
    "padder = padding.PKCS7(128).padder()",
    "padded = padder.update(message) + padder.finalize()",
    "cbc_cipher = Cipher(algorithms.AES(key), modes.CBC(iv))",
    "cbc_ct = cbc_cipher.encryptor().update(padded) + cbc_cipher.encryptor().finalize()",
    "",
    "# Decrypt + unpad to confirm.",
    "decryptor = Cipher(algorithms.AES(key), modes.CBC(iv)).decryptor()",
    "cbc_pt = decryptor.update(cbc_ct) + decryptor.finalize()",
    "unpadder = padding.PKCS7(128).unpadder()",
    "cbc_pt = unpadder.update(cbc_pt) + unpadder.finalize()",
    "assert cbc_pt == message",
    "",
    "# ---------------------------------------------------------------",
    "# CTR — turn AES into a stream cipher. No padding needed; ciphertext",
    "# length equals plaintext length. NEVER reuse (key, nonce).",
    "# ---------------------------------------------------------------",
    "nonce = os.urandom(16)",
    "ctr_cipher = Cipher(algorithms.AES(key), modes.CTR(nonce))",
    "ctr_ct = ctr_cipher.encryptor().update(message) + ctr_cipher.encryptor().finalize()",
    "ctr_pt = Cipher(algorithms.AES(key), modes.CTR(nonce)).decryptor()",
    "ctr_pt = ctr_pt.update(ctr_ct) + ctr_pt.finalize()",
    "assert ctr_pt == message",
    "",
    "# ---------------------------------------------------------------",
    "# GCM — CTR + a polynomial MAC (GHASH). Output is (ciphertext, 16-byte tag).",
    "# The high-level AESGCM API hides the tag inside the returned blob.",
    "# Nonce-reuse here is catastrophic: it leaks plaintext AND breaks auth.",
    "# ---------------------------------------------------------------",
    "aesgcm = AESGCM(key)",
    "gcm_nonce = os.urandom(12)   # 96-bit nonce is the GCM standard",
    "gcm_ct = aesgcm.encrypt(gcm_nonce, message, None)   # 3rd arg = associated data",
    "gcm_pt = aesgcm.decrypt(gcm_nonce, gcm_ct, None)",
    "assert gcm_pt == message",
    "",
    "print(\"key       :\", key.hex())",
    "print(\"CBC ct    :\", cbc_ct.hex())",
    "print(\"CTR ct    :\", ctr_ct.hex())",
    "print(\"GCM ct+tag:\", gcm_ct.hex())",
  ].join("\n");
}

